            <div className="bg-white rounded-[2rem] shadow-2xl w-full max-w-sm relative z-10 overflow-hidden animate-in zoom-in-95 duration-300 border border-white/20">
                <div className="p-8 text-center">
                    <div className="w-16 h-16 bg-red-50 rounded-full flex items-center justify-center mx-auto mb-6 shadow-inner">
                        <AlertTriangle className="w-8 h-8 text-red-500" />
                    </div>
                    <h3 className="text-2xl font-black text-gray-800 mb-2">Delete Resume?</h3>
                    <p className="text-gray-500 text-sm mb-8 leading-relaxed">
                        This will remove the file and unlink extraction data. This action cannot be undone.
                    </p>
                    <div className="grid grid-cols-2 gap-3">
                         <button 
                            onClick={() => setShowDeleteModal(false)}
                            className="py-3 bg-gray-100 hover:bg-gray-200 text-gray-700 font-bold rounded-xl transition-colors text-sm"
                        >
                            Cancel
                        </button>
                        <button 
                            onClick={confirmDeleteResume}
                            disabled={deletingResume}
                            className="py-3 bg-red-500 hover:bg-red-600 text-white font-bold rounded-xl shadow-lg shadow-red-200 transition-all text-sm flex items-center justify-center gap-2"
                        >
                            {deletingResume ? <Loader2 size={16} className="animate-spin" /> : "Yes, Delete"}
                        </button>
                    </div>
                </div>
            </div>
        </div>
    )}

    {/* Global Success Toast */}
    {savedSuccess && (
        <div className="fixed top-6 right-6 z-[100] animate-in slide-in-from-top-5 fade-in duration-300">
            <div className="bg-white/90 backdrop-blur-md border border-green-100 text-green-800 px-6 py-4 rounded-2xl shadow-2xl flex items-center gap-3">
                <div className="bg-green-100 p-1 rounded-full"><CheckCircle size={16} className="text-luGreen"/></div>
                <span className="font-bold text-sm">Profile saved successfully!</span>
            </div>
        </div>
    )}

    </>
  );
};

export default MyProfilePage;

import React, { useEffect, useState } from 'react';
import { LogOut, User, BookOpen, Calendar, MapPin, Award, Bell, Search, ChevronDown, Briefcase, LayoutDashboard, Save, Loader2, CheckCircle, Plus, Trash2, Edit2, X, RefreshCw, Building2, ToggleLeft, ToggleRight, Clock, HelpCircle, AlertTriangle } from 'lucide-react';
import { Student, EmploymentFormState, EmploymentRecord, EmploymentStatus } from '../types';
import { supabase } from '../lib/supabaseClient';
import { analyzeJobDetails } from '../services/employmentAI';

interface EmploymentStatusPageProps {
  user: Student;
}

const EmploymentStatusPage: React.FC<EmploymentStatusPageProps> = ({ user }) => {
  const [submitting, setSubmitting] = useState(false);
  const [loadingRecords, setLoadingRecords] = useState(false);
  const [employmentRecords, setEmploymentRecords] = useState<EmploymentRecord[]>([]);

  // View State
  const [viewMode, setViewMode] = useState<'list' | 'form'>('list');
  const [selectedStatus, setSelectedStatus] = useState<EmploymentStatus | null>(null);
  const [showStatusSelector, setShowStatusSelector] = useState(false);

  // New: Record View Toggle
  const [recordViewType, setRecordViewType] = useState<'Employed' | 'Self-employed'>('Employed');

  // New: Non-Related Detection State
  const [isNonRelatedDetected, setIsNonRelatedDetected] = useState(false);

  // New: Confirmation Modal State
  const [showConfirmModal, setShowConfirmModal] = useState(false);
  const [pendingAiResult, setPendingAiResult] = useState<any>(null);

  // Form State
  const initialFormState: EmploymentFormState = {
    employment_status: '',
    current_position: '',
    date_hired: '',
    company_name: '',
    company_address: '',
    business_name: '',
    business_address: '',
    business_type: '',
    business_contact_no: '',
    unemployed_reasons: '',
    last_company: '',
    retirement_reason: '',
    date_retired: '',
    business_duration: '',
    alignment_reason: ''
  };
  const [formData, setFormData] = useState<EmploymentFormState>(initialFormState);

  // --- Data Fetching ---
  const fetchEmploymentRecords = async () => {
    setLoadingRecords(true);
    try {
        if (!user.id) {
            console.warn("User ID is missing, cannot fetch records.");
            return;
        }

        const idColumn = user.enrollment_status === 'Graduating' ? 'student_id' : 'alumni_id';

        // 1. Get Survey Responses IDs for this user
        const { data: surveys, error: surveyError } = await supabase
            .from('survey_responses')
            .select('id')
            .eq(idColumn, user.id);

        if (surveyError) {
            console.error("Error fetching surveys:", JSON.stringify(surveyError));
            throw new Error(surveyError.message);
        }

        if (!surveys || surveys.length === 0) {
            setEmploymentRecords([]);
            setLoadingRecords(false);
            setShowStatusSelector(true); // Show selector if no records
            return;
        }

        const surveyIds = surveys.map(s => s.id);

        // 2. Get Employment Info linked to those surveys
        const { data: records, error: recordsError } = await supabase
            .from('employment_information')
            .select('*')
            .in('survey_response_id', surveyIds)
            .order('id', { ascending: false }); // Latest first

        if (recordsError) {
             console.error("Error fetching employment info:", JSON.stringify(recordsError));
             throw new Error(recordsError.message);
        }

        const typedRecords = records as EmploymentRecord[];
        setEmploymentRecords(typedRecords);

        // Logic for Initial View State
        if (typedRecords.length > 0) {
            // Check if we have both types
            const hasEmployed = typedRecords.some(r => r.employment_status === 'Employed');
            const hasSelfEmployed = typedRecords.some(r => r.employment_status === 'Self-employed');

            if (hasEmployed && !hasSelfEmployed) setRecordViewType('Employed');
            else if (!hasEmployed && hasSelfEmployed) setRecordViewType('Self-employed');
            else setRecordViewType('Employed'); // Default if both or neither

            // For the big status display, we use the most recent one, but UI handles dual display now
            setSelectedStatus(typedRecords[0].employment_status as EmploymentStatus);
            setShowStatusSelector(false);
        } else {
            setShowStatusSelector(true);
        }

    } catch (error: any) {
        console.error("Error fetching records:", error.message || error);
    } finally {
        setLoadingRecords(false);
    }
  };

  useEffect(() => {
    fetchEmploymentRecords();
  }, [user.id]); // Re-fetch if user changes, basically on mount

  // Reset detection when crucial fields change
  useEffect(() => {
    if (viewMode === 'form') {
        setIsNonRelatedDetected(false);
    }
  }, [formData.current_position, formData.company_name, formData.business_name, formData.business_type]);


  // --- Event Handlers ---

  const handleStatusSelect = (status: EmploymentStatus) => {
      // Logic: Selecting a status opens the form to add a record for that status
      setFormData({ ...initialFormState, employment_status: status });
      setViewMode('form');
      setShowStatusSelector(false);
      setIsNonRelatedDetected(false);
  };

  const handleAddJob = () => {
      setFormData({ ...initialFormState, employment_status: 'Employed' });
      setViewMode('form');
      setIsNonRelatedDetected(false);
  };

  const handleAddBusiness = () => {
      setFormData({ ...initialFormState, employment_status: 'Self-employed' });
      setViewMode('form');
      setIsNonRelatedDetected(false);
  };

  const handleEdit = (record: EmploymentRecord) => {
      setFormData(record);
      setViewMode('form');
      setIsNonRelatedDetected(record.job_alignment === 'Non-Related');
  };

  const handleDelete = async (id: string) => {
      if (!confirm("Are you sure you want to delete this record?")) return;
      try {
          const { error } = await supabase.from('employment_information').delete().eq('id', id);
          if (error) throw error;
          fetchEmploymentRecords();
      } catch (error) {
          console.error("Error deleting record:", error);
          alert("Failed to delete record.");
      }
  };

  const handleInputChange = (field: keyof EmploymentFormState, value: string) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  // 1. First Step: AI Analysis and Validation
  const handlePreSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setSubmitting(true);

    try {
      if (!user.id) throw new Error("User ID missing");

      let aiResult = { job_alignment: 'Non-Related', current_job_level: 'Rank and File', industry: 'Unclassified' };

      // 1. AI Analysis (Only if Employed/Self-Employed)
      if (formData.employment_status === 'Employed') {
        // @ts-ignore
        aiResult = await analyzeJobDetails(formData.current_position, formData.company_name, user.program, 'Employed');
      } else if (formData.employment_status === 'Self-employed') {
        // @ts-ignore
        aiResult = await analyzeJobDetails('Owner/Proprietor', formData.business_name, user.program, 'Self-employed');
      }

      // 2. Non-Related Check
      // If AI says non-related and user hasn't provided a reason yet, stop submission and show field
      if (aiResult.job_alignment === 'Non-Related' && !formData.alignment_reason && 
         (formData.employment_status === 'Employed' || formData.employment_status === 'Self-employed')) {
          setIsNonRelatedDetected(true);
          setSubmitting(false);
          // We can optionally scroll to the field here if needed
          return;
      }

      // 3. Validation Passed -> Prompt Confirmation
      setPendingAiResult(aiResult);
      setShowConfirmModal(true);
      setSubmitting(false);

    } catch (err: any) {
      console.error("Submission error:", err);
      alert("Failed to analyze information: " + err.message);
      setSubmitting(false);
    }
  };

  // 2. Second Step: Actual Database Commit
  const executeFinalSave = async () => {
    setSubmitting(true);
    const aiResult = pendingAiResult || { job_alignment: 'Non-Related', current_job_level: 'Rank and File', industry: 'Unclassified' };

    try {
      const respondentType = user.enrollment_status === 'Graduating' ? 'student' : 'alumni';
      let surveyResponseId = '';

      if (formData.id) {
          // UPDATE EXISTING RECORD
          const updatePayload: any = {
              employment_status: formData.employment_status,

              job_alignment: (formData.employment_status === 'Employed' || formData.employment_status === 'Self-employed') ? aiResult.job_alignment : null,
              current_job_level: (formData.employment_status === 'Employed' || formData.employment_status === 'Self-employed') ? aiResult.current_job_level : null,
              industry: (formData.employment_status === 'Employed' || formData.employment_status === 'Self-employed') ? aiResult.industry : null,

              current_position: formData.employment_status === 'Employed' ? formData.current_position : null,
              date_hired: formData.employment_status === 'Employed' ? formData.date_hired : null,
              company_name: formData.employment_status === 'Employed' ? formData.company_name : null,
              company_address: formData.employment_status === 'Employed' ? formData.company_address : null,

              business_name: formData.employment_status === 'Self-employed' ? formData.business_name : null,
              business_address: formData.employment_status === 'Self-employed' ? formData.business_address : null,
              business_type: formData.employment_status === 'Self-employed' ? formData.business_type : null,
              business_contact_no: formData.employment_status === 'Self-employed' ? formData.business_contact_no : null,
              business_duration: formData.employment_status === 'Self-employed' ? formData.business_duration : null,

              unemployed_reasons: formData.employment_status === 'Unemployed' ? formData.unemployed_reasons : null,

              last_company: formData.employment_status === 'Retired' ? formData.last_company : null,
              retirement_reason: formData.employment_status === 'Retired' ? formData.retirement_reason : null,
              date_retired: formData.employment_status === 'Retired' ? formData.date_retired : null,

              // Save alignment reason ONLY if AI says Non-Related
              alignment_reason: ((formData.employment_status === 'Employed' || formData.employment_status === 'Self-employed') && aiResult.job_alignment === 'Non-Related') ? formData.alignment_reason : null,
          };

          const { error } = await supabase.from('employment_information').update(updatePayload).eq('id', formData.id);
          if (error) throw error;

      } else {
          // CREATE NEW RECORD
          const surveyPayload: any = {
            respondent_type: respondentType,
            submitted_at: new Date().toISOString()
          };
          if (respondentType === 'student') surveyPayload.student_id = user.id;
          else surveyPayload.alumni_id = user.id;

          const { data: surveyData, error: surveyError } = await supabase
            .from('survey_responses')
            .insert([surveyPayload])
            .select()
            .single();

          if (surveyError) throw surveyError;
          surveyResponseId = surveyData.id;

          const insertPayload = {
            survey_response_id: surveyResponseId,
            employment_status: formData.employment_status,

            job_alignment: (formData.employment_status === 'Employed' || formData.employment_status === 'Self-employed') ? aiResult.job_alignment : null,
            current_job_level: (formData.employment_status === 'Employed' || formData.employment_status === 'Self-employed') ? aiResult.current_job_level : null,
            industry: (formData.employment_status === 'Employed' || formData.employment_status === 'Self-employed') ? aiResult.industry : null,

            current_position: formData.employment_status === 'Employed' ? formData.current_position : null,
            date_hired: formData.employment_status === 'Employed' ? formData.date_hired : null,
            company_name: formData.employment_status === 'Employed' ? formData.company_name : null,
            company_address: formData.employment_status === 'Employed' ? formData.company_address : null,

            business_name: formData.employment_status === 'Self-employed' ? formData.business_name : null,
            business_address: formData.employment_status === 'Self-employed' ? formData.business_address : null,
            business_type: formData.employment_status === 'Self-employed' ? formData.business_type : null,
            business_contact_no: formData.employment_status === 'Self-employed' ? formData.business_contact_no : null,
            business_duration: formData.employment_status === 'Self-employed' ? formData.business_duration : null,

            unemployed_reasons: formData.employment_status === 'Unemployed' ? formData.unemployed_reasons : null,

            last_company: formData.employment_status === 'Retired' ? formData.last_company : null,
            retirement_reason: formData.employment_status === 'Retired' ? formData.retirement_reason : null,
            date_retired: formData.employment_status === 'Retired' ? formData.date_retired : null,

            alignment_reason: ((formData.employment_status === 'Employed' || formData.employment_status === 'Self-employed') && aiResult.job_alignment === 'Non-Related') ? formData.alignment_reason : null,
          };

          const { error: empError } = await supabase.from('employment_information').insert([insertPayload]);
          if (empError) throw empError;
      }

      await fetchEmploymentRecords();
      setViewMode('list');
      setIsNonRelatedDetected(false);
      setShowConfirmModal(false);

    } catch (err: any) {
      console.error("Submission error:", err);
      alert("Failed to save information: " + err.message);
    } finally {
      setSubmitting(false);
    }
  };

  const cancelForm = () => {
      setViewMode('list');
      if (employmentRecords.length > 0) {
          setShowStatusSelector(false);
      }
      setIsNonRelatedDetected(false);
  };

  // Status Logic
  const hasEmployed = employmentRecords.some(r => r.employment_status === 'Employed');
  const hasSelfEmployed = employmentRecords.some(r => r.employment_status === 'Self-employed');
  const hasUnemployed = employmentRecords.some(r => r.employment_status === 'Unemployed');
  const hasRetired = employmentRecords.some(r => r.employment_status === 'Retired');

  // Filter Logic
  const filteredRecords = employmentRecords.filter(record => {
      if (recordViewType === 'Employed') return record.employment_status === 'Employed';
      if (recordViewType === 'Self-employed') return record.employment_status === 'Self-employed';
      return false;
  });

  // RENDER JSX
  return (
    <>
    <div className="bg-white rounded-3xl shadow-sm border border-gray-100 overflow-hidden animate-slide-up relative min-h-[500px]">
        <div className="p-8 border-b border-gray-100 bg-gradient-to-r from-gray-50 to-white flex justify-between items-center">
            <div className="flex items-center gap-4">
                    <div className="p-3 bg-amber-100 text-amber-600 rounded-xl">
                    <Briefcase size={28} />
                    </div>
                    <div>
                    <h3 className="text-2xl font-bold text-gray-800 font-display">Employment Status</h3>
                    <p className="text-sm text-gray-500 mt-1">Manage your professional journey.</p>
                    </div>
            </div>
            {viewMode === 'form' && (
                <button onClick={cancelForm} className="flex items-center gap-2 bg-gray-100 text-gray-600 px-4 py-2 rounded-xl text-sm font-bold hover:bg-gray-200 transition-all">
                    <X size={16} /> Cancel
                </button>
            )}
        </div>

        {/* Content Body */}
        <div className="p-8">
            {loadingRecords ? (
                    <div className="flex flex-col items-center justify-center py-12 text-gray-400">
                    <Loader2 className="w-8 h-8 animate-spin mb-2" />
                    <p>Loading records...</p>
                </div>
            ) : viewMode === 'list' ? (
                <div className="space-y-8 animate-fade-in">

                    {/* Current Status & Header Section */}
                    {employmentRecords.length > 0 && !showStatusSelector && (
                        <div className="bg-green-50 rounded-2xl p-6 border border-green-100 flex flex-col md:flex-row justify-between items-center gap-4">
                            <div>
                                <h4 className="text-xs font-bold text-gray-500 uppercase tracking-widest mb-1">Current Status</h4>
                                <div className="flex items-center gap-3">
                                    <div className="p-2 rounded-lg bg-green-200 text-luGreen-dark">
                                        <Briefcase size={20} />
                                    </div>
                                    <span className="text-xl font-bold text-gray-800">
                                        {hasEmployed && hasSelfEmployed ? 'Employed & Self-employed' :
                                            hasEmployed ? 'Employed' :
                                            hasSelfEmployed ? 'Self-employed' :
                                            hasUnemployed ? 'Unemployed' :
                                            hasRetired ? 'Retired' : 'Unknown'}
                                    </span>
                                </div>
                            </div>

                            <div className="flex gap-2 w-full md:w-auto">
                                {/* Allow adding both types if one is active, or both */}
                                {(hasEmployed || hasSelfEmployed) && (
                                    <>
                                    <button onClick={handleAddJob} className="flex-1 md:flex-initial flex items-center justify-center gap-2 bg-white text-gray-700 border border-gray-200 hover:border-blue-300 hover:text-blue-600 px-4 py-2.5 rounded-xl text-sm font-bold shadow-sm transition-all">
                                        <Plus size={16} /> Add Job
                                    </button>
                                    <button onClick={handleAddBusiness} className="flex-1 md:flex-initial flex items-center justify-center gap-2 bg-white text-gray-700 border border-gray-200 hover:border-purple-300 hover:text-purple-600 px-4 py-2.5 rounded-xl text-sm font-bold shadow-sm transition-all">
                                        <Plus size={16} /> Add Business
                                    </button>
                                    </>
                                )}
                                <button 
                                    onClick={() => setShowStatusSelector(true)}
                                    className="flex-1 md:flex-initial flex items-center justify-center gap-2 bg-gray-800 text-white px-4 py-2.5 rounded-xl text-sm font-bold shadow-md hover:bg-gray-900 transition-all"
                                >
                                    <RefreshCw size={16} /> Update Status
                                </button>
                            </div>
                        </div>
                    )}

                    {/* Status Selector - Only shown if requested or no records */}
                    {showStatusSelector && (
                        <div className="p-6 bg-gray-50 rounded-2xl border border-gray-100 animate-slide-up">
                            <div className="flex justify-between items-center mb-4">
                                <h4 className="text-sm font-bold text-gray-700 uppercase tracking-wider">
                                    {employmentRecords.length > 0 ? 'Update your Employment Status' : 'Choose your Current Status'}
                                </h4>
                                {employmentRecords.length > 0 && (
                                    <button onClick={() => setShowStatusSelector(false)} className="text-xs font-bold text-gray-400 hover:text-gray-600">Cancel</button>
                                )}
                            </div>
                            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                                {['Employed', 'Self-employed', 'Unemployed', 'Retired'].map((status) => (
                                    <button
                                        key={status}
                                        onClick={() => handleStatusSelect(status as EmploymentStatus)}
                                        className={`py-4 px-4 rounded-xl text-sm font-bold border-2 transition-all duration-200 flex flex-col items-center gap-2 hover:bg-white hover:border-gray-200 hover:shadow-md ${
                                            selectedStatus === status 
                                            ? 'border-luGreen bg-white text-luGreen shadow-md ring-2 ring-luGreen/20' 
                                            : 'border-transparent bg-gray-200/50 text-gray-500'
                                        }`}
                                    >
                                        {status === 'Employed' && <Briefcase size={24} />}
                                        {status === 'Self-employed' && <Award size={24} />}
                                        {status === 'Unemployed' && <Bell size={24} />}
                                        {status === 'Retired' && <User size={24} />}
                                        {status}
                                    </button>
                                ))}
                            </div>
                        </div>
                    )}

                    {/* Toggle Switch for Records - Only if both exist */}
                    {hasEmployed && hasSelfEmployed && !showStatusSelector && (
                        <div className="flex justify-center mb-6">
                            <div className="bg-gray-100 p-1 rounded-xl flex shadow-inner">
                                <button
                                    onClick={() => setRecordViewType('Employed')}
                                    className={`px-6 py-2 rounded-lg text-sm font-bold transition-all ${recordViewType === 'Employed' ? 'bg-white text-blue-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
                                >
                                    Employed Records
                                </button>
                                <button
                                    onClick={() => setRecordViewType('Self-employed')}
                                    className={`px-6 py-2 rounded-lg text-sm font-bold transition-all ${recordViewType === 'Self-employed' ? 'bg-white text-purple-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
                                >
                                    Self-Employed Records
                                </button>
                            </div>
                        </div>
                    )}

                    {/* Records List */}
                    {employmentRecords.length > 0 && !showStatusSelector && (
                        <div>
                            <h4 className="text-sm font-bold text-gray-700 uppercase tracking-wider mb-4 border-b border-gray-100 pb-2">Employment Records</h4>
                            <div className="space-y-4">
                                {/* Combine filtered records + other records (unemployed/retired) so they don't disappear */}
                                {[...(hasEmployed && hasSelfEmployed ? filteredRecords : employmentRecords)].map((record) => (
                                    <div key={record.id} className="bg-white border border-gray-100 p-5 rounded-2xl shadow-sm hover:shadow-md transition-shadow relative group">
                                        <div className="absolute top-4 right-4 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                                            <button onClick={() => handleEdit(record)} className="p-2 text-blue-500 bg-blue-50 rounded-lg hover:bg-blue-100"><Edit2 size={14}/></button>
                                            <button onClick={() => handleDelete(record.id)} className="p-2 text-red-500 bg-red-50 rounded-lg hover:bg-red-100"><Trash2 size={14}/></button>
                                        </div>

                                        <div className="flex items-start gap-4">
                                            <div className={`p-3 rounded-xl flex-shrink-0 ${
                                                record.employment_status === 'Employed' ? 'bg-blue-50 text-blue-600' :
                                                record.employment_status === 'Self-employed' ? 'bg-purple-50 text-purple-600' :
                                                record.employment_status === 'Unemployed' ? 'bg-red-50 text-red-600' : 'bg-gray-100 text-gray-600'
                                            }`}>
                                                {record.employment_status === 'Employed' && <Briefcase size={20} />}
                                                {record.employment_status === 'Self-employed' && <Award size={20} />}
                                                {record.employment_status === 'Unemployed' && <Bell size={20} />}
                                                {record.employment_status === 'Retired' && <User size={20} />}
                                            </div>
                                            <div className="flex-grow">
                                                <div className="flex items-center gap-2 mb-1">
                                                    <span className="text-xs font-bold uppercase tracking-wider text-gray-400 border border-gray-200 px-2 py-0.5 rounded-full">{record.employment_status}</span>
                                                    {record.industry && <span className="text-xs font-bold uppercase tracking-wider text-luGreen border border-green-100 bg-green-50 px-2 py-0.5 rounded-full">{record.industry}</span>}
                                                </div>

                                                {record.employment_status === 'Employed' && (
                                                    <>
                                                        <h5 className="text-lg font-bold text-gray-800">{record.current_position}</h5>
                                                        <p className="text-sm text-gray-600">{record.company_name} • {record.company_address}</p>
                                                        <div className="flex gap-4 mt-2 text-xs text-gray-500 flex-wrap">
                                                            <span>Hired: {record.date_hired}</span>
                                                            {record.job_alignment && <span>Alignment: <strong className={record.job_alignment === 'Related' ? 'text-green-600' : 'text-amber-600'}>{record.job_alignment}</strong></span>}
                                                            {record.current_job_level && <span>Level: <strong>{record.current_job_level}</strong></span>}
                                                            {record.alignment_reason && <span>Reason: <strong>{record.alignment_reason}</strong></span>}
                                                        </div>
                                                    </>
                                                )}
                                                {record.employment_status === 'Self-employed' && (
                                                    <>
                                                        <h5 className="text-lg font-bold text-gray-800">{record.business_name}</h5>
                                                        <p className="text-sm text-gray-600">{record.business_type} • {record.business_address}</p>
                                                        <div className="flex gap-4 mt-2 text-xs text-gray-500 flex-wrap">
                                                                {record.business_duration && <span>Duration: <strong>{record.business_duration}</strong></span>}
                                                                {record.job_alignment && <span>Alignment: <strong className={record.job_alignment === 'Related' ? 'text-green-600' : 'text-amber-600'}>{record.job_alignment}</strong></span>}
                                                                {record.alignment_reason && <span>Reason: <strong>{record.alignment_reason}</strong></span>}
                                                        </div>
                                                    </>
                                                )}
                                                {record.employment_status === 'Unemployed' && (
                                                    <p className="text-sm text-gray-600 italic mt-1">"{record.unemployed_reasons}"</p>
                                                )}
                                                {record.employment_status === 'Retired' && (
                                                    <>
                                                        <h5 className="text-lg font-bold text-gray-800">Retired from {record.last_company}</h5>
                                                        <p className="text-sm text-gray-500 mt-1">Date: {record.date_retired}</p>
                                                    </>
                                                )}
                                            </div>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    )}
                </div>
            ) : (
                // FORM MODE
                <form onSubmit={handlePreSubmit} className="space-y-6 animate-fade-in max-w-3xl mx-auto">
                    <div className="text-center mb-6">
                        <span className="inline-block px-4 py-1 bg-luGreen text-white text-xs font-bold rounded-full uppercase tracking-wide mb-2">{formData.employment_status}</span>
                        <h3 className="text-xl font-bold text-gray-800">
                            {formData.id ? 'Edit Record' : 'Add New Record'}
                        </h3>
                    </div>

                    {formData.employment_status === 'Employed' && (
                        <div className="space-y-6">
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                <div className="space-y-2">
                                    <label className="text-xs font-bold text-gray-500 uppercase">Current Position / Job Title</label>
                                    <input required type="text" value={formData.current_position} onChange={e => handleInputChange('current_position', e.target.value)} className="w-full px-4 py-3 rounded-xl bg-gray-50 border border-gray-200 focus:border-luGreen focus:outline-none" placeholder="e.g. Software Engineer" />
                                </div>
                                <div className="space-y-2">
                                    <label className="text-xs font-bold text-gray-500 uppercase">Date Hired</label>
                                    <input required type="date" value={formData.date_hired} onChange={e => handleInputChange('date_hired', e.target.value)} className="w-full px-4 py-3 rounded-xl bg-gray-50 border border-gray-200 focus:border-luGreen focus:outline-none" />
                                </div>
                                <div className="space-y-2">
                                    <label className="text-xs font-bold text-gray-500 uppercase">Company Name</label>
                                    <input required type="text" value={formData.company_name} onChange={e => handleInputChange('company_name', e.target.value)} className="w-full px-4 py-3 rounded-xl bg-gray-50 border border-gray-200 focus:border-luGreen focus:outline-none" placeholder="e.g. Google Inc." />
                                </div>
                                <div className="space-y-2">
                                    <label className="text-xs font-bold text-gray-500 uppercase">Company Address</label>
                                    <input required type="text" value={formData.company_address} onChange={e => handleInputChange('company_address', e.target.value)} className="w-full px-4 py-3 rounded-xl bg-gray-50 border border-gray-200 focus:border-luGreen focus:outline-none" placeholder="City, Country" />
                                </div>

                                {isNonRelatedDetected && (
                                    <div className="col-span-1 md:col-span-2 space-y-2 animate-fade-in bg-amber-50 p-4 rounded-xl border border-amber-100">
                                        <label className="text-xs font-bold text-amber-800 uppercase flex items-center gap-1">
                                            <HelpCircle size={12} /> System detected this role is Non-Related. Please state reason:
                                        </label>
                                        <select value={formData.alignment_reason || ''} onChange={e => handleInputChange('alignment_reason', e.target.value)} className="w-full px-4 py-3 rounded-xl bg-white border border-amber-200 focus:border-luGreen focus:outline-none">
                                            <option value="">-- Select Reason --</option>
                                            <option value="Better Salary/Benefits">Better Salary & Benefits</option>
                                            <option value="Career Advancement">Career Advancement</option>
                                            <option value="Limited Job Opportunity in Field">Limited Job Opportunity in Field</option>
                                            <option value="Family Influence">Family Influence</option>
                                            <option value="Proximity to Residence">Proximity to Residence</option>
                                            <option value="Career Shift / Passion">Career Shift / Passion</option>
                                        </select>
                                    </div>
                                )}
                            </div>
                            <div className="p-4 bg-blue-50 rounded-xl flex items-start gap-3 border border-blue-100">
                                <div className="bg-white p-2 rounded-full shadow-sm text-blue-500">
                                    <Briefcase size={16} />
                                </div>
                                <div className="text-sm text-blue-800">
                                    <p className="font-bold">AI Analysis Active</p>
                                    <p className="opacity-80 mt-1">Our system will automatically determine Industry, Job Level, and Course Alignment.</p>
                                </div>
                            </div>
                        </div>
                    )}

                    {formData.employment_status === 'Self-employed' && (
                        <div className="space-y-6">
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                <div className="space-y-2">
                                    <label className="text-xs font-bold text-gray-500 uppercase">Business Name</label>
                                    <input required type="text" value={formData.business_name} onChange={e => handleInputChange('business_name', e.target.value)} className="w-full px-4 py-3 rounded-xl bg-gray-50 border border-gray-200 focus:border-luGreen focus:outline-none" />
                                </div>
                                <div className="space-y-2">
                                    <label className="text-xs font-bold text-gray-500 uppercase">Business Type</label>
                                    <input required type="text" value={formData.business_type} onChange={e => handleInputChange('business_type', e.target.value)} className="w-full px-4 py-3 rounded-xl bg-gray-50 border border-gray-200 focus:border-luGreen focus:outline-none" placeholder="e.g. Retail, Consulting" />
                                </div>
                                <div className="space-y-2">
                                    <label className="text-xs font-bold text-gray-500 uppercase">Business Address</label>
                                    <input required type="text" value={formData.business_address} onChange={e => handleInputChange('business_address', e.target.value)} className="w-full px-4 py-3 rounded-xl bg-gray-50 border border-gray-200 focus:border-luGreen focus:outline-none" />
                                </div>
                                <div className="space-y-2">
                                    <label className="text-xs font-bold text-gray-500 uppercase">Contact Number</label>
                                    <input required type="text" value={formData.business_contact_no} onChange={e => handleInputChange('business_contact_no', e.target.value)} className="w-full px-4 py-3 rounded-xl bg-gray-50 border border-gray-200 focus:border-luGreen focus:outline-none" />
                                </div>
                                <div className="space-y-2">
                                    <label className="text-xs font-bold text-gray-500 uppercase">Duration of Operation</label>
                                    <input required type="text" value={formData.business_duration || ''} onChange={e => handleInputChange('business_duration', e.target.value)} className="w-full px-4 py-3 rounded-xl bg-gray-50 border border-gray-200 focus:border-luGreen focus:outline-none" placeholder="e.g. 2 years" />
                                </div>

                                {isNonRelatedDetected && (
                                    <div className="space-y-2 animate-fade-in bg-amber-50 p-4 rounded-xl border border-amber-100">
                                        <label className="text-xs font-bold text-amber-800 uppercase flex items-center gap-1">
                                            <HelpCircle size={12} /> System detected this role is Non-Related. Please state reason:
                                        </label>
                                        <select value={formData.alignment_reason || ''} onChange={e => handleInputChange('alignment_reason', e.target.value)} className="w-full px-4 py-3 rounded-xl bg-white border border-amber-200 focus:border-luGreen focus:outline-none">
                                            <option value="">-- Select Reason --</option>
                                            <option value="Better Financials">Better Financials</option>
                                            <option value="Family Business">Family Business</option>
                                            <option value="Passion / Hobby">Passion / Hobby</option>
                                            <option value="No Job Opportunity">No Job Opportunity</option>
                                        </select>
                                    </div>
                                )}
                            </div>
                        </div>
                    )}

                    {formData.employment_status === 'Unemployed' && (
                        <div className="space-y-6">
                            <div className="space-y-2">
                                <label className="text-xs font-bold text-gray-500 uppercase">Reason for Unemployment</label>
                                <textarea required rows={4} value={formData.unemployed_reasons} onChange={e => handleInputChange('unemployed_reasons', e.target.value)} className="w-full px-4 py-3 rounded-xl bg-gray-50 border border-gray-200 focus:border-luGreen focus:outline-none" placeholder="Please share your reasons..." />
                            </div>
                        </div>
                    )}

                    {formData.employment_status === 'Retired' && (
                        <div className="space-y-6">
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                <div className="space-y-2">
                                    <label className="text-xs font-bold text-gray-500 uppercase">Last Company</label>
                                    <input required type="text" value={formData.last_company} onChange={e => handleInputChange('last_company', e.target.value)} className="w-full px-4 py-3 rounded-xl bg-gray-50 border border-gray-200 focus:border-luGreen focus:outline-none" />
                                </div>
                                <div className="space-y-2">
                                    <label className="text-xs font-bold text-gray-500 uppercase">Date Retired</label>
                                    <input required type="date" value={formData.date_retired} onChange={e => handleInputChange('date_retired', e.target.value)} className="w-full px-4 py-3 rounded-xl bg-gray-50 border border-gray-200 focus:border-luGreen focus:outline-none" />
                                </div>
                                <div className="col-span-1 md:col-span-2 space-y-2">
                                    <label className="text-xs font-bold text-gray-500 uppercase">Retirement Reason</label>
                                    <textarea required rows={2} value={formData.retirement_reason} onChange={e => handleInputChange('retirement_reason', e.target.value)} className="w-full px-4 py-3 rounded-xl bg-gray-50 border border-gray-200 focus:border-luGreen focus:outline-none" />
                                </div>
                            </div>
                        </div>
                    )}

                    <div className="pt-6 border-t border-gray-100 flex gap-4">
                        <button 
                            type="submit" 
                            disabled={submitting}
                            className="flex-1 px-8 py-3 bg-luGreen text-white font-bold rounded-xl shadow-lg hover:bg-luGreen-dark hover:shadow-xl transition-all flex items-center justify-center gap-2"
                        >
                            {submitting ? (
                                <>
                                    <Loader2 className="animate-spin w-5 h-5" />
                                    <span>Processing...</span>
                                </>
                            ) : (
                                <>
                                    <Save size={20} />
                                    <span>Save Record</span>
                                </>
                            )}
                        </button>
                            <button 
                            type="button" 
                            onClick={cancelForm}
                            className="px-6 py-3 bg-white border border-gray-200 text-gray-600 font-bold rounded-xl hover:bg-gray-50 transition-all"
                        >
                            Cancel
                        </button>
                    </div>
                </form>
            )}
        </div>
    </div>

    {/* === CONFIRMATION MODAL === */}
    {showConfirmModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-gray-900/40 backdrop-blur-sm animate-in fade-in duration-300"></div>
            <div className="bg-white rounded-[2rem] shadow-2xl w-full max-w-sm relative z-10 overflow-hidden animate-in zoom-in-95 duration-300 border border-white/20">
                <div className="p-8 text-center">
                    <div className={`w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-6 shadow-inner ${
                        formData.employment_status === 'Unemployed' ? 'bg-red-50 text-red-500' :
                        formData.employment_status === 'Retired' ? 'bg-gray-100 text-gray-500' :
                        'bg-blue-50 text-blue-500'
                    }`}>
                        <AlertTriangle className="w-8 h-8" />
                    </div>
                    <h3 className="text-xl font-black text-gray-800 mb-2">Confirm Update?</h3>
                    <p className="text-gray-500 text-sm mb-6 leading-relaxed">
                        Are you sure you want to update your employment status to <strong className="text-gray-900">{formData.employment_status}</strong>?
                    </p>

                    <div className="grid grid-cols-2 gap-3">
                         <button 
                            onClick={() => setShowConfirmModal(false)}
                            className="py-3 bg-gray-100 hover:bg-gray-200 text-gray-700 font-bold rounded-xl transition-colors text-sm"
                        >
                            Cancel
                        </button>
                        <button 
                            onClick={executeFinalSave}
                            disabled={submitting}
                            className="py-3 bg-luGreen hover:bg-luGreen-dark text-white font-bold rounded-xl shadow-lg shadow-green-200 transition-all text-sm flex items-center justify-center gap-2"
                        >
                            {submitting ? <Loader2 size={16} className="animate-spin" /> : "Yes, Save"}
                        </button>
                    </div>
                </div>
            </div>
        </div>
    )}
    </>
  );
};

export default EmploymentStatusPage;
